import { useNavigate } from "react-router-dom";

export default function Home() {
  const nav = useNavigate();

  const trains = [
    { name: "Vande Bharat", base: 1500 },
    { name: "Rajdhani Express", base: 1800 },
    { name: "Shatabdi Express", base: 1600 },
    { name: "Garib Rath", base: 1000 },
  ];

  return (
    <div style={{ padding:"30px" }}>
      {trains.map((t, i) => (
        <div key={i} className="card">
          <h2>{t.name}</h2>
          <p>Price: ₹{t.base} - ₹{t.base * 4}</p>
          <button onClick={()=>nav(`/booking/${t.name}/${t.base}`)}>
            Book Now
          </button>
        </div>
      ))}
    </div>
  );
}
